import React, { useState } from 'react';
import { Card, Button, Form, Alert, ListGroup, Table, Badge } from 'react-bootstrap';
import axios from 'axios';

function CustomerCard() {
  const [phone, setPhone] = useState('');
  const [customer, setCustomer] = useState(null);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const token = localStorage.getItem('token');
  const API_URL = 'http://localhost:5051/api';

  const searchCustomer = async () => {
    if (!phone.trim()) return;
    setLoading(true);
    setError('');
    setOrders([]);
    
    try {
      // Ищем клиента
      const response = await axios.get(`${API_URL}/Customers/search?term=${phone}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      if (response.data.length > 0) {
        setCustomer(response.data[0]);
        // Загружаем историю заказов
        loadCustomerOrders(response.data[0].id);
      } else {
        setCustomer(null);
        setError('Клиент не найден');
      }
    } catch (err) {
      setError('Ошибка поиска');
    }
    setLoading(false);
  };

  const loadCustomerOrders = async (customerId) => {
    try {
      const response = await axios.get(`${API_URL}/Orders`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      // Фильтруем заказы клиента
      const customerOrders = response.data.filter(o => o.customerName === customer?.fullName);
      setOrders(customerOrders);
    } catch (err) {
      console.error('Ошибка загрузки заказов');
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'New': return <Badge bg="primary">Новый</Badge>;
      case 'Paid': return <Badge bg="success">Оплачен</Badge>;
      case 'Shipped': return <Badge bg="info">Отгружен</Badge>;
      default: return <Badge bg="secondary">{status}</Badge>;
    }
  };

  return (
    <div>
      <h2 className="mb-4">👤 Карточка клиента</h2>
      
      <Card className="mb-4">
        <Card.Body>
          <Form.Group className="mb-3">
            <Form.Label>Поиск по телефону</Form.Label>
            <div className="d-flex">
              <Form.Control
                placeholder="Введите телефон"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && searchCustomer()}
              />
              <Button variant="primary" onClick={searchCustomer} disabled={loading} className="ms-2">
                🔍 Найти
              </Button>
            </div>
          </Form.Group>
        </Card.Body>
      </Card>

      {error && <Alert variant="danger">{error}</Alert>}

      {customer && (
        <>
          <Card className="mb-4 border-primary">
            <Card.Header className="bg-primary text-white">
              <strong>👤 {customer.fullName}</strong>
            </Card.Header>
            <Card.Body>
              <p>📞 {customer.phone}</p>
              <p>📧 {customer.email || 'Не указан'}</p>
              <p>🚗 {customer.carModel || 'Не указан'} {customer.carYear || ''}</p>
              <p className="text-muted">
                Всего заказов: <strong>{orders.length}</strong>
              </p>
            </Card.Body>
          </Card>

          <Card>
            <Card.Header><strong>📋 История заказов</strong></Card.Header>
            <Card.Body>
              {orders.length > 0 ? (
                <Table striped hover>
                  <thead>
                    <tr>
                      <th>Номер</th>
                      <th>Дата</th>
                      <th>Сумма</th>
                      <th>Статус</th>
                    </tr>
                  </thead>
                  <tbody>
                    {orders.map(order => (
                      <tr key={order.id}>
                        <td>{order.orderNumber}</td>
                        <td>{new Date(order.orderDate).toLocaleDateString('ru-RU')}</td>
                        <td>{order.totalAmount.toFixed(2)} ₽</td>
                        <td>{getStatusBadge(order.status)}</td>
                      </tr>
                    ))}
                  </tbody>
                </Table>
              ) : (
                <div className="text-center text-muted py-3">
                  Заказов пока нет
                </div>
              )}
            </Card.Body>
          </Card>
        </>
      )}
    </div>
  );
}

export default CustomerCard;
